#include<bits/stdc++.h>
using namespace std;
#define int long long

const int N = 1e6 + 5;
const double INF = 1e20;

struct Point {
    int x, y;
} p[N], tmp[N], sorted_y[N];

bool cmpx(Point a, Point b) {
    return a.x < b.x;
}

double dist_sqr(Point a, Point b) {
    int dx = a.x - b.x;
    int dy = a.y - b.y;
    return (double)dx * dx + (double)dy * dy;
}

double closest_pair(int l, int r) {
    if (l >= r) return INF;
    if (l + 1 == r) {
        if (p[l].y > p[r].y) swap(p[l], p[r]);
        return dist_sqr(p[l], p[r]);
    }

    int mid = (l + r) / 2;
    int mid_x = p[mid].x;

    double d = min(closest_pair(l, mid), closest_pair(mid + 1, r));

    int i = l, j = mid + 1, k = l;
    while (i <= mid && j <= r) {
        if (p[i].y < p[j].y) sorted_y[k++] = p[i++];
        else sorted_y[k++] = p[j++];
    }
    while (i <= mid) sorted_y[k++] = p[i++];
    while (j <= r) sorted_y[k++] = p[j++];

    for (int i = l; i <= r; i++) p[i] = sorted_y[i];

    int cnt = 0;
    for (int i = l; i <= r; i++) {
        if ((double)(p[i].x - mid_x) * (p[i].x - mid_x) < d) tmp[cnt++] = p[i];
    }

    for (int i = 0; i < cnt; i++) {
        for (int j = i + 1; j < cnt && (double)(tmp[j].y - tmp[i].y) * (tmp[j].y - tmp[i].y) < d; j++) {
            d = min(d, dist_sqr(tmp[i], tmp[j]));
        }
    }
    return d;
}

signed main() {
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) cin >> p[i].x >> p[i].y;
    sort(p, p + n, cmpx);
    printf("%.0lf\n", closest_pair(0, n - 1));
    return 0;
}
